  ('locality-6e2f88c7-moex-00039', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依司法院大法官解釋意旨，下列何者非屬法規之制定或發布時無信賴保護原則適用之情形？', '["經廢止或變更之法規有重大明顯違反上位規範情形者", "相關法規係因主張權益受害者提供不正確資料而發布", "純屬法規適用對象主觀之願望而未有表現已生信賴之事實者", "相關法規之訂定並未有法律之明確授權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "f5ea59b35ed7", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00040', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '法律為防止盤商囤積雞蛋，以平抑蛋價及滿足民生需求，對違法囤積者每一盒處罰新臺幣 2,500 元，某盤商經主管機關查獲囤積大量雞蛋而被裁處上億元罰鍰，依司法院大法官解釋意旨，此種 裁罰結果最可能牴觸比例原則之何項子原則？', '["正當立法目的", "適當性原則", "必要性原則", "狹義比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "f5ea59b35ed7", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00041', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '有關公用地役關係之敘述，下列何者正確？', '["公用地役關係因行政機關所為之行政處分而創設", "具公用地役關係之現有巷道，於喪失其原有功能或已無繼續供公眾通行之必要時，公用地役關 係自動消滅", "土地成立公用地役關係之所有權人對於國家有土地使用費之請求權", "行政機關廢止公用地役關係，其性質屬一般處分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "f5ea59b35ed7", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00042', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '有關行政組織之敘述，下列何者正確？', '["獨立機關為依據公法設立而具有公法上權利能力者", "中央選舉委員會為合議制機關", "中小學校家長會屬於學校之行政組織", "金融監督管理委員會為獨立機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "f5ea59b35ed7", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00043', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '下列何者非屬地方制度法所稱之委辦事項？', '["內政部將有關外國人入出國、停留、居留、永久居留、收容管理及驅逐出國等業務，委由各直 轄市、縣（市）政府辦理", "宜蘭縣政府將核發土地使用分區證明書之權限，委由其轄區內鄉鎮市公所辦理", "臺北市政府將部分涉及捷運管理之業務交由新北市政府辦理", "內政部將土地徵收補償費、遷移費的查估委由各直轄市或縣（市）政府辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "f5ea59b35ed7", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
