  ('locality-6e2f88c7-moex-00045', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依公務員懲戒法規定，下列敘述何者正確？', '["受降級處分者，自改敘之日起，4年內不得晉敘、陞任或遷調主管職務", "申誡處分，得以口頭方式為之，受申誡人請求，方須作成書面", "罰款之懲戒處分不得與剝奪、減少退休（職、伍）金之懲戒處分併為處分", "剝奪、減少退休（職、伍）金之懲戒處分，得對現任公務員將來之退休（職、伍）金扣減之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "f5ea59b35ed7", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
